    /**
     * @method
     * @name kucoin#watchOrderBookForSymbols
     * @see https://www.kucoin.com/docs-new/3470069w0 // spot level 5
     * @see https://www.kucoin.com/docs-new/3470070w0 // spot level 50
     * @see https://www.kucoin.com/docs-new/3470068w0 // spot incremental
     * @see https://www.kucoin.com/docs-new/3470083w0 // futures level 5
     * @see https://www.kucoin.com/docs-new/3470097w0 // futures level 50
     * @see https://www.kucoin.com/docs-new/3470082w0 // futures incremental
     * @see https://www.kucoin.com/docs-new/3470221w0 // uta
     * @description watches information on open orders with bid (buy) and ask (sell) prices, volumes and other data
     * @param {string[]} symbols unified array of symbols
     * @param {int} [limit] the maximum amount of order book entries to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} A dictionary of [order book structures]{@link https://docs.ccxt.com/?id=order-book-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchOrderBookForSymbols(Object symbols2, Object... optionalArgs)
    {
        final Object symbols3 = symbols2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object symbols = symbols3;
            Object limit = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            Object symbolsLength = Helpers.getArrayLength(symbols);
            if (Helpers.isTrue(Helpers.isEqual(symbolsLength, 0)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " watchOrderBookForSymbols() requires a non-empty array of symbols")) ;
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(limit, 20))) && Helpers.isTrue((!Helpers.isEqual(limit, 100)))) && Helpers.isTrue((!Helpers.isEqual(limit, 50)))) && Helpers.isTrue((!Helpers.isEqual(limit, 5)))))
                {
                    throw new ExchangeError((String)Helpers.add(this.id, " watchOrderBook 'limit' argument must be undefined, 5, 20, 50 or 100")) ;
                }
            }
            (this.loadMarkets()).join();
            symbols = this.marketSymbols(symbols);
            Object marketIds = this.marketIds(symbols);
            Object firstMarket = this.getMarketFromSymbols(symbols);
            Object isFuturesMethod = Helpers.GetValue(firstMarket, "contract");
            Object url = (this.negotiate(false, isFuturesMethod)).join();
            Object method = ((Helpers.isTrue(isFuturesMethod))) ? "/contractMarket/level2" : "/market/level2";
            Object optionName = ((Helpers.isTrue(isFuturesMethod))) ? "contractMethod" : "spotMethod";
            var methodparametersVariable = this.handleOptionAndParams2(parameters, "watchOrderBook", optionName, "method", method);
            method = ((java.util.List<Object>) methodparametersVariable).get(0);
            parameters = ((java.util.List<Object>) methodparametersVariable).get(1);
            if (Helpers.isTrue(Helpers.isEqual(Helpers.getIndexOf(method, "Depth"), Helpers.opNeg(1))))
            {
                if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(limit, 5))) || Helpers.isTrue((Helpers.isEqual(limit, 50)))))
                {
                    if (!Helpers.isTrue(isFuturesMethod))
                    {
                        method = "/spotMarket/level2";
                    }
                    method = Helpers.add(method, Helpers.add("Depth", String.valueOf(limit)));
                }
            }
            Object topic = Helpers.add(Helpers.add(method, ":"), String.join((String)",", (java.util.List<String>)marketIds));
            Object messageHashes = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object subscriptionHashes = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(symbols)); i++)
            {
                Object symbol = Helpers.GetValue(symbols, i);
                ((java.util.List<Object>)messageHashes).add(Helpers.add("orderbook:", symbol));
                Object marketId = Helpers.GetValue(marketIds, i);
                ((java.util.List<Object>)subscriptionHashes).add(Helpers.add(Helpers.add(method, ":"), marketId));
            }
            Object subscription = new java.util.HashMap<String, Object>() {{}};
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(method, "/market/level2"))) || Helpers.isTrue((Helpers.isEqual(method, "/contractMarket/level2")))))
            {
                final Object finalSymbols = symbols;
                final Object finalLimit = limit;
                subscription = new java.util.HashMap<String, Object>() {{
                    put( "method", "handleOrderBookSubscription");
                    put( "symbols", finalSymbols );
                    put( "limit", finalLimit );
                }};
            }
            Object orderbook = (this.subscribeMultiple(url, messageHashes, topic, subscriptionHashes, parameters, subscription)).join();
            return Helpers.callDynamically(orderbook, "limit", new Object[]{});
        });

    }

