    /**
     * @method
     * @name kucoin#watchOrders
     * @description watches information on multiple orders made by the user
     * @see https://www.kucoin.com/docs-new/3470074w0 // spot regular orders
     * @see https://www.kucoin.com/docs-new/3470139w0 // spot trigger orders
     * @see https://www.kucoin.com/docs-new/3470090w0 // contract regular orders
     * @see https://www.kucoin.com/docs-new/3470091w0 // contract trigger orders
     * @see https://www.kucoin.com/docs-new/3470228w0 // uta orders
     * @param {string} symbol unified market symbol of the market orders were made in
     * @param {int} [since] the earliest time in ms to fetch orders for
     * @param {int} [limit] the maximum number of order structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {boolean} [params.uta] set to true for the unified trading account (uta)
     * @param {boolean} [params.trigger] trigger orders are watched if true
     * @param {string} [params.type] 'spot' or 'swap' (default is 'spot' if symbol is not provided)
     * @returns {object[]} a list of [order structures]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchOrders(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object uta = (this.isUTAEnabled()).join();
            var utaparametersVariable = this.handleOptionAndParams(parameters, "watchOrders", "uta", uta);
            uta = ((java.util.List<Object>) utaparametersVariable).get(0);
            parameters = ((java.util.List<Object>) utaparametersVariable).get(1);
            Object market = null;
            Object messageHash = "orders";
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                market = this.market(symbol);
                symbol = Helpers.GetValue(market, "symbol");
                messageHash = Helpers.add(Helpers.add(messageHash, ":"), symbol);
            }
            Object orders = null;
            if (Helpers.isTrue(uta))
            {
                parameters = this.extend(parameters, new java.util.HashMap<String, Object>() {{
                    put( "tradeType", "UNIFIED" );
                }});
                messageHash = Helpers.add("uta:", messageHash);
                Object channel = "order";
                if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
                {
                    channel = Helpers.add(channel, "All");
                }
                orders = (this.subscribePrivateUta(new java.util.ArrayList<Object>(java.util.Arrays.asList(messageHash)), messageHash, channel, symbol, parameters)).join();
            } else
            {
                Object trigger = this.safeBool2(parameters, "stop", "trigger");
                parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("stop", "trigger")));
                Object marketType = null;
                var marketTypeparametersVariable = this.handleMarketTypeAndParams("watchOrders", market, parameters);
                marketType = ((java.util.List<Object>) marketTypeparametersVariable).get(0);
                parameters = ((java.util.List<Object>) marketTypeparametersVariable).get(1);
                Object isFuturesMethod = (Helpers.isTrue((!Helpers.isEqual(marketType, "spot"))) && Helpers.isTrue((!Helpers.isEqual(marketType, "margin"))));
                Object url = (this.negotiate(true, isFuturesMethod)).join();
                Object topic = ((Helpers.isTrue(trigger))) ? "/spotMarket/advancedOrders" : "/spotMarket/tradeOrders";
                if (Helpers.isTrue(isFuturesMethod))
                {
                    topic = ((Helpers.isTrue(trigger))) ? "/contractMarket/advancedOrders" : "/contractMarket/tradeOrders";
                }
                if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
                {
                    Object suffix = this.getOrdersMessageHashSuffix(topic);
                    messageHash = Helpers.add(messageHash, suffix);
                }
                Object request = new java.util.HashMap<String, Object>() {{
                    put( "privateChannel", true );
                }};
                orders = (this.subscribe(url, messageHash, topic, this.extend(request, parameters))).join();
            }
            if (Helpers.isTrue(this.newUpdates))
            {
                limit = Helpers.callDynamically(orders, "getLimit", new Object[]{symbol, limit});
            }
            return this.filterBySymbolSinceLimit(orders, symbol, since, limit, true);
        });

    }

    public Object getOrdersMessageHashSuffix(Object topic)
    {
        Object suffix = "-spot";
        if (Helpers.isTrue(Helpers.isEqual(topic, "/spotMarket/advancedOrders")))
        {
            suffix = Helpers.add(suffix, "-trigger");
        } else if (Helpers.isTrue(Helpers.isEqual(topic, "/contractMarket/tradeOrders")))
        {
            suffix = "-contract";
        } else if (Helpers.isTrue(Helpers.isEqual(topic, "/contractMarket/advancedOrders")))
        {
            suffix = "-contract-trigger";
        }
        return suffix;
    }

    public Object parseWsOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "open", "open" );
            put( "filled", "closed" );
            put( "match", "open" );
            put( "update", "open" );
            put( "canceled", "canceled" );
            put( "cancel", "canceled" );
            put( "TRIGGERED", "triggered" );
        }};
        return this.safeString(statuses, status, status);
    }

    public Object parseWsOrder(Object order, Object... optionalArgs)
    {
        //
        // /spotMarket/tradeOrders
        //
        //    {
        //        "symbol": "XCAD-USDT",
        //        "orderType": "limit",
        //        "side": "buy",
        //        "orderId": "6249167327218b000135e749",
        //        "type": "canceled",
        //        "orderTime": 1648957043065280224,
        //        "size": "100.452",
        //        "filledSize": "0",
        //        "price": "2.9635",
        //        "clientOid": "buy-XCAD-USDT-1648957043010159",
        //        "remainSize": "0",
        //        "status": "done",
        //        "ts": 1648957054031001037
        //    }
        //
        // /spotMarket/advancedOrders
        //
        //    {
        //        "createdAt": 1589789942337,
        //        "orderId": "5ec244f6a8a75e0009958237",
        //        "orderPrice": "0.00062",
        //        "orderType": "stop",
        //        "side": "sell",
        //        "size": "1",
        //        "stop": "entry",
        //        "stopPrice": "0.00062",
        //        "symbol": "KCS-BTC",
        //        "tradeType": "TRADE",
        //        "triggerSuccess": true,
        //        "ts": 1589790121382281286,
        //        "type": "triggered"
        //    }
        //
        // futures
        //     {
        //         "symbol": "ETHUSDTM",
        //         "orderType": "market",
        //         "side": "buy",
        //         "canceledSize": "0",
        //         "orderId": "416204113500479490",
        //         "positionSide": "LONG",
        //         "liquidity": "taker",
        //         "marginMode": "ISOLATED",
        //         "type": "match",
        //         "feeType": "takerFee",
        //         "orderTime": "1772043995356345762",
        //         "size": "1",
        //         "filledSize": "1",
        //         "price": "0",
        //         "matchPrice": "2068.55",
        //         "matchSize": "1",
        //         "remainSize": "0",
        //         "tradeId": "1815302608109",
        //         "clientOid": "9f7a2be0-effe-45bd-bdc8-1614715a583a",
        //         "tradeType": "trade",
        //         "status": "match",
        //         "ts": 1772043995362000000
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object rawType = this.safeString(order, "type");
        Object status = this.parseWsOrderStatus(rawType);
        Object timestamp = this.safeInteger2(order, "orderTime", "createdAt");
        Object marketId = this.safeString(order, "symbol");
        market = this.safeMarket(marketId, market);
        if (Helpers.isTrue(Helpers.GetValue(market, "contract")))
        {
            timestamp = this.safeIntegerProduct(order, "orderTime", 0.000001);
        }
        Object triggerPrice = this.safeString(order, "stopPrice");
        Object triggerSuccess = this.safeBool(order, "triggerSuccess");
        Object triggerFail = Helpers.isTrue((!Helpers.isEqual(triggerSuccess, true))) && Helpers.isTrue((!Helpers.isEqual(triggerSuccess, null))); // TODO: updated to triggerSuccess === False once transpiler transpiles it correctly
        if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(status, "triggered"))) && Helpers.isTrue(triggerFail)))
        {
            status = "canceled";
        }
        final Object finalMarket = market;
        final Object finalTimestamp = timestamp;
        final Object finalStatus = status;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "id", KucoinCore.this.safeString(order, "orderId") );
            put( "clientOrderId", KucoinCore.this.safeString(order, "clientOid") );
            put( "timestamp", finalTimestamp );
            put( "datetime", KucoinCore.this.iso8601(finalTimestamp) );
            put( "lastTradeTimestamp", null );
            put( "type", KucoinCore.this.safeStringLower(order, "orderType") );
            put( "timeInForce", null );
            put( "postOnly", null );
            put( "side", KucoinCore.this.safeStringLower(order, "side") );
            put( "price", KucoinCore.this.safeString2(order, "price", "orderPrice") );
            put( "stopPrice", triggerPrice );
            put( "triggerPrice", triggerPrice );
            put( "amount", KucoinCore.this.safeString(order, "size") );
            put( "cost", null );
            put( "average", null );
            put( "filled", KucoinCore.this.safeString(order, "filledSize") );
            put( "remaining", null );
            put( "status", finalStatus );
            put( "fee", null );
            put( "trades", null );
        }}, market);
    }

